UPDATE user
username = #{username}, password = #{password}, name = #{name}, description = #{description}, avatar_url = #{avatarUrl}, following_count = #{followingCount}, followers_count = #{followersCount}, update_time = NOW(),
WHERE id = #{id}

mapper.select:
SELECT interests
