SELECT id, username, name, description, avatar_url AS avatarUrl, following_count AS followingCount, followers_count AS followersCount, create_time AS createTime, update_time AS updateTime FROM user
AND (username LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{offset}, #{size}
